import { MakeLogicType, actions, afterMount, isBreakpoint, kea, listeners, path, reducers, selectors } from 'kea'
import { loaders } from 'kea-loaders'

import { lemonToast } from '@posthog/lemon-ui'

import api from 'lib/api'

import type { SignalReportPriority, SignalTeamConfig } from '../types'

/** A single `org/repo` → base-branch override, flattened for rendering. */
export interface BaseBranchOverride {
    repo: string
    branch: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface signalTeamConfigLogicValues {
    autostartEnabled: boolean
    baseBranchOverrides: BaseBranchOverride[]
    defaultAutostartPriority: SignalReportPriority
    draftBaseBranchBranch: string
    draftBaseBranchRepo: string
    teamConfig: SignalTeamConfig | null
    teamConfigLoading: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface signalTeamConfigLogicActions {
    addBaseBranchOverride: () => {
        value: true
    }
    clearDraftBaseBranch: () => {
        value: true
    }
    loadTeamConfig: () => any
    loadTeamConfigFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadTeamConfigSuccess: (
        teamConfig: SignalTeamConfig,
        payload?: any
    ) => {
        teamConfig: SignalTeamConfig
        payload?: any
    }
    patchTeamConfig: (patch: Partial<SignalTeamConfig>) => {
        patch: Partial<SignalTeamConfig>
    }
    removeBaseBranchOverride: (repo: string) => {
        repo: string
    }
    setDraftBaseBranchBranch: (branch: string) => {
        branch: string
    }
    setDraftBaseBranchRepo: (repo: string) => {
        repo: string
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface signalTeamConfigLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        autostartEnabled: (teamConfig: SignalTeamConfig | null) => boolean
        defaultAutostartPriority: (teamConfig: SignalTeamConfig | null) => SignalReportPriority
        baseBranchOverrides: (teamConfig: SignalTeamConfig | null) => BaseBranchOverride[]
    }
}

export type signalTeamConfigLogicType = MakeLogicType<
    signalTeamConfigLogicValues,
    signalTeamConfigLogicActions,
    Record<string, any>,
    signalTeamConfigLogicMeta
>

/**
 * Team-level Self-driving config (singleton per team). Wraps the
 * `signals/team_config` endpoint via `api.signalTeamConfig`. Surfaces the
 * team-wide default PR auto-start threshold (which seeds every user's effective
 * threshold until they set a personal override in `userAutonomyLogic`) and the
 * team-wide default Slack notification channel, where every actionable report is
 * posted regardless of whether a suggested reviewer resolves. The auto-start
 * field is non-nullable (P0–P4), so unlike the per-user override there is no
 * "Never" option; the channel is nullable and `null` disables the team default.
 */
export const signalTeamConfigLogic = kea<signalTeamConfigLogicType>([
    path(['scenes', 'inbox', 'logics', 'signalTeamConfigLogic']),
    actions({
        // Partial update of the singleton, e.g. `{ default_slack_notification_channel: null }`
        // to clear the team channel. One action serves every patchable field.
        patchTeamConfig: (patch: Partial<SignalTeamConfig>) => ({ patch }),
        // Draft inputs for the "add a base-branch override" row, committed via addBaseBranchOverride.
        setDraftBaseBranchRepo: (repo: string) => ({ repo }),
        setDraftBaseBranchBranch: (branch: string) => ({ branch }),
        clearDraftBaseBranch: true,
        addBaseBranchOverride: true,
        removeBaseBranchOverride: (repo: string) => ({ repo }),
    }),
    loaders({
        teamConfig: [
            null as SignalTeamConfig | null,
            {
                loadTeamConfig: async () => {
                    return await api.signalTeamConfig.get()
                },
            },
        ],
    }),
    reducers({
        // Optimistically reflect the patched values so the controls don't flicker
        // back to the stale ones while the request is in flight.
        teamConfig: {
            patchTeamConfig: (state, { patch }) => (state ? { ...state, ...patch } : state),
        },
        draftBaseBranchRepo: [
            '',
            {
                setDraftBaseBranchRepo: (_, { repo }) => repo,
                clearDraftBaseBranch: () => '',
            },
        ],
        draftBaseBranchBranch: [
            '',
            {
                setDraftBaseBranchBranch: (_, { branch }) => branch,
                clearDraftBaseBranch: () => '',
            },
        ],
    }),
    selectors({
        // Master switch for autonomous inbox PRs: only an explicit false disables
        // auto-start, so a team that never touched the setting stays on.
        autostartEnabled: [
            (s) => [s.teamConfig],
            (teamConfig: SignalTeamConfig | null): boolean => teamConfig?.autostart_enabled !== false,
        ],
        defaultAutostartPriority: [
            (s) => [s.teamConfig],
            (teamConfig: SignalTeamConfig | null): SignalReportPriority =>
                teamConfig?.default_autostart_priority ?? 'P4',
        ],
        // Flatten the `org/repo` → branch map into a stably-sorted list for rendering.
        baseBranchOverrides: [
            (s) => [s.teamConfig],
            (teamConfig: SignalTeamConfig | null): BaseBranchOverride[] =>
                Object.entries(teamConfig?.autostart_base_branches ?? {})
                    .map(([repo, branch]) => ({ repo, branch }))
                    .sort((a, b) => a.repo.localeCompare(b.repo)),
        ],
    }),
    listeners(({ actions, values }) => ({
        // Merge the draft repo/branch into the map and persist the whole map (the API replaces
        // the field wholesale). Mirrors the backend's normalization: lowercased 'org/repo' key,
        // trimmed branch, and the same 'exactly one slash, both parts non-empty' shape check so
        // the user gets inline feedback instead of a round-tripped 400.
        addBaseBranchOverride: () => {
            const repo = values.draftBaseBranchRepo.trim().toLowerCase()
            const branch = values.draftBaseBranchBranch.trim()
            const parts = repo.split('/')
            if (parts.length !== 2 || parts.some((part) => !part)) {
                lemonToast.error("Repository must be in 'organization/repository' form")
                return
            }
            if (!branch) {
                lemonToast.error('Enter a base branch name')
                return
            }
            const next = { ...values.teamConfig?.autostart_base_branches, [repo]: branch }
            actions.patchTeamConfig({ autostart_base_branches: next })
            actions.clearDraftBaseBranch()
        },
        removeBaseBranchOverride: ({ repo }) => {
            const next = { ...values.teamConfig?.autostart_base_branches }
            delete next[repo]
            actions.patchTeamConfig({ autostart_base_branches: next })
        },
        patchTeamConfig: async ({ patch }, breakpoint) => {
            try {
                const config = await api.signalTeamConfig.update(patch)
                // A newer patch was dispatched while this one was in flight — drop the
                // stale response so out-of-order arrivals can't overwrite the latest value.
                breakpoint()
                actions.loadTeamConfigSuccess(config)
            } catch (error: any) {
                if (isBreakpoint(error)) {
                    throw error
                }
                lemonToast.error(error?.detail ?? error?.message ?? 'Failed to update team self-driving settings')
                // Resync so the optimistic value doesn't linger after a failed update.
                actions.loadTeamConfig()
            }
        },
    })),
    afterMount(({ actions }) => {
        actions.loadTeamConfig()
    }),
])
